{"content":"import type { Comment, Post } from '@/types';

const JSON_PLACEHOLDER_BASE_URL = 'https://jsonplaceholder.typicode.com';

export async function fetchPosts(limit?: number): Promise<Post[]> {
  const search = typeof limit === 'number' ? `?_limit=${limit}` : '';
  const response = await fetch(`${JSON_PLACEHOLDER_BASE_URL}/posts${search}`, {
    next: limit ? { revalidate: 0 } : { revalidate: 60 },
  });

  if (!response.ok) {
    throw new Error('Failed to fetch posts');
  }

  return response.json() as Promise<Post[]>;
}

export async function fetchPost(id: string): Promise<Post | null> {
  const response = await fetch(`${JSON_PLACEHOLDER_BASE_URL}/posts/${id}`, {
    next: { revalidate: 300 },
  });

  if (response.status === 404) {
    return null;
  }

  if (!response.ok) {
    throw new Error(`Failed to fetch post ${id}`);
  }

  return response.json() as Promise<Post>;
}

export async function fetchComments(id: string): Promise<Comment[]> {
  const response = await fetch(`${JSON_PLACEHOLDER_BASE_URL}/posts/${id}/comments`, {
    next: { revalidate: 300 },
  });

  if (!response.ok) {
    throw new Error(`Failed to fetch comments for post ${id}`);
  }

  return response.json() as Promise<Comment[]>;
}
