  padding: 20px;
  border-radius: 8px;
}

.post-card h2 {
  margin-bottom: 10px;
}

.post-card a {
  text-decoration: none;
  color: #333;
}

.post-card a:hover {
  color: #0070f3;
}

.comments {
  margin-top: 30px;
}

.comment {
  border: 1px solid #eee;
  padding: 15px;
  margin-bottom: 15px;
  border-radius: 8px;
}

.comment h3 {
  margin-bottom: 5px;
  font-size: 16px;
}

.comment small {
  color: #666;
}

.error-page {
  text-align: center;
  padding: 100px 20px;
}

